mpting", "skills/11/title": "Multimodal Prompting", "skills/12/title": "Prompt Engineering", "skills/13/title": "Gemini", "skills/14/title": "Google Cloud Platform (GCP)", "skills/15/title": "Microsoft Copilot", "skills/16/title": "Adobe Creative Cloud", "skills/17/title": "Google Analytics", "skills/18/title": "ChatGPT", "skills/19/title": "Chatbot Development", "totalExperienceYears": "36.8", "totalRecommendationsGiven": "0", "totalRecommendationsReceived": "0", "updates/0/postLink": "https://www.linkedin.com/feed/update/urn:li:activity:7021835149537353728?updateEntityUrn=urn%3Ali%3Afs_feedUpdate%3A%28V2%2Curn%3Ali%3Aactivity%3A7021835149537353728%29", "updates/0/postText": "𝙍𝙤𝙖𝙙 𝙩𝙧𝙞𝙥𝙨 𝙖𝙧𝙚 𝙢𝙮 𝙥𝙖𝙨𝙨𝙞𝙤𝙣.\n\nExploring Thailand Beyond the Map\nAs a Level 10 Google Local Guide, I’ve explored and documented hundreds of destinations across Thailand — from mountain villages to coastal islands.\n\nMore than 1,000 reviews and 25,000 photos have reached over 150 million views, forming a living archive of the country’s cultural and natural diversity.\n\nFor me, exploration isn’t tourism — it’s fieldwork in storytelling: understanding how people, places, and experiences connect.\n\nVisit my Google profile: https://lnkd.in/d_P2tS5P\n\n#RoadTripThailand | #GoogleMapsExplorer | #RealThailand | #MappedByMads | #PhotoDrivenTravel | #HiddenThailand", "updates/0/type": "Post", "urn": "ACoAAD-bSvEBBekwN0fPs0P9jHR08s5ILxOJU2s"}$$::jsonb),
